# --- SECURE: Server-side route registry (allowlist approach) ---

# Define allowed redirect destinations using route identifiers, not arbitrary URLs.
# Each entry maps a route_id to a Flask endpoint name and optional parameters.
ALLOWED_REDIRECT_ROUTES = {
    'dashboard': {'endpoint': 'dashboard'},
    'profile': {'endpoint': 'profile'},
    'settings': {'endpoint': 'settings'},
    'home': {'endpoint': 'home'},
    'reports': {'endpoint': 'reports'},
    'admin_panel': {'endpoint': 'admin_panel'},
}

# Default redirect after login if no valid destination is specified
DEFAULT_POST_LOGIN_ROUTE = 'dashboard'


def validate_redirect_destination(route_id):
    """
    Validate that a redirect destination is in our allowlist.
    Returns the route_id if valid, or the default route if not.
    
    SECURE: Only allows predefined server-side route identifiers.
    NEVER redirects to arbitrary user-supplied URLs.
    """
    if route_id and route_id in ALLOWED_REDIRECT_ROUTES:
        return route_id
    return DEFAULT_POST_LOGIN_ROUTE


def resolve_route_url(route_id):
    """
    Resolve a validated route_id to an actual URL using Flask's url_for.
    This ensures URLs are always generated server-side.
    """
    route_info = ALLOWED_REDIRECT_ROUTES.get(route_id)
    if route_info is None:
        route_info = ALLOWED_REDIRECT_ROUTES[DEFAULT_POST_LOGIN_ROUTE]
    
    endpoint = route_info['endpoint']
    params = route_info.get('params', {})
    
    try:
        return url_for(endpoint, **params)
    except Exception:
        return url_for(ALLOWED_REDIRECT_ROUTES[DEFAULT_POST_LOGIN_ROUTE]['endpoint'])


def is_safe_url(url):
    """
    Additional safety check: ensure a URL is relative and points to our own host.
    This is a defense-in-depth measure, not the primary protection.
    
    SECURE: Rejects absolute URLs to external hosts.
    """
    if not url:
        return False
    
    parsed = urlparse(url)
    
    # Reject absolute URLs with a scheme (http://, https://, javascript:, etc.)
    if parsed.scheme:
        return False
    
    # Reject protocol-relative URLs (//evil.com/path)
    if url.startswith('//'):
        return False
    
    # Reject URLs with netloc (host component)
    if parsed.netloc:
        return False
    
    # Only allow paths that start with /
    if not parsed.path.startswith('/'):
        return False
    
    return True


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            # Store the intended destination as a route_id, not a raw URL
            # Try to find the current endpoint in our allowlist
            intended_route = None
            for route_id, route_info in ALLOWED_REDIRECT_ROUTES.items():
                if route_info['endpoint'] == request.endpoint:
                    intended_route = route_id
                    break
            
            if intended_route:
                session['intended_destination'] = intended_route
            
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def perform_login_redirect():
    """
    Perform a secure post-login redirect.
    
    SECURE approach:
    1. Check session for a stored route_id (set by login_required decorator)
    2. Check query parameter 'next' but treat it as a route_id, NOT a URL
    3. Validate against the allowlist
    4. Generate the URL server-side using url_for
    5. Fall back to default destination
    """
    # Priority 1: Check session for intended destination (most secure)
    intended = session.pop('intended_destination', None)
    
    # Priority 2: Check query parameter, but ONLY as a route identifier
    if not intended:
        intended = request.args.get('next', '')
    
    # SECURE: Validate against allowlist - never trust raw input
    validated_route = validate_redirect_destination(intended)
    
    # Generate URL server-side from the validated route identifier
    redirect_url = resolve_route_url(validated_route)
    
    # Defense in depth: verify the generated URL is safe
    if not is_safe_url(redirect_url):
        redirect_url = resolve_route_url(DEFAULT_POST_LOGIN_ROUTE)
    
    return redirect(redirect_url)


