@app.route('/login', methods=['GET', 'POST'])
def login():
    error = None
    
    # Get the intended destination from query params (as route_id only)
    next_route = request.args.get('next', '')
    # Validate it immediately - don't pass through unvalidated
    if next_route and next_route not in ALLOWED_REDIRECT_ROUTES:
        next_route = ''
    
    intended_from_session = session.get('intended_destination', '')
    
    if request.method == 'POST':
        username = request.form.get('username', '')
        password = request.form.get('password', '')
        
        # INSECURE EXAMPLE (DO NOT DO THIS):
        # raw_url = request.form.get('next', '')
        # return redirect(raw_url)  # NEVER redirect to user-supplied URLs!
        
        if username in USERS and USERS[username] == password:
            session['authenticated'] = True
            session['username'] = username
            
            # If form has a next parameter, store it as intended destination
            form_next = request.form.get('next', '')
            if form_next and form_next in ALLOWED_REDIRECT_ROUTES:
                session['intended_destination'] = form_next
            
            # SECURE: Use our validated redirect function
            return perform_login_redirect()
        else:
            error = 'Invalid username or password.'
    
    return render_template_string(
        LOGIN_TEMPLATE,
        error=error,
        next_route=next_route or intended_from_session,
        intended=intended_from_session or next_route,
    )


