@app.route('/demo/attack-prevention')
def demo_attack_prevention():
    """
    Demonstrates how the secure redirect prevents open redirect attacks.
    """
    test_cases = [
        ('dashboard', 'Valid route_id'),
        ('profile', 'Valid route_id'),
        ('https://evil.com', 'Malicious absolute URL - will be rejected'),
        ('//evil.com/steal-cookies', 'Protocol-relative URL - will be rejected'),
        ('javascript:alert(1)', 'JavaScript injection - will be rejected'),
        ('', 'Empty - will use default'),
        ('../../../etc/passwd', 'Path traversal - will be rejected'),
        ('settings', 'Valid route_id'),
        ('nonexistent_page', 'Unknown route_id - will use default'),
    ]
    
    results = []
    for test_input, description in test_cases:
        validated = validate_redirect_destination(test_input)
        resolved_url = resolve_route_url(validated)
        safe = is_safe_url(resolved_url)
        results.append({
            'input': test_input,
            'description': description,
            'validated_route': validated,
            'resolved_url': resolved_url,
            'is_safe': safe,
        })
    
    html = '<h1>Open Redirect Attack Prevention Demo</h1>'
    html += '<table border="1" cellpadding="8" cellspacing="0">'
    html += '<tr><th>Input</th><th>Description</th><th>Validated Route</th>'
    html += '<th>Resolved URL</th><th>Safe?</th></tr>'
    
    for r in results:
        color = 'green' if r['is_safe'] else 'red'
        html += f'''<tr>
            <td><code>{r["input"]}</code></td>
            <td>{r["description"]}</td>
            <td><code>{r["validated_route"]}</code></td>
            <td><code>{r["resolved_url"]}</code></td>
            <td style="color: {color}; font-weight: bold;">{r["is_safe"]}</td>
        </tr>'''
    
    html += '</table>'
    html += f'<br><a href="{url_for("home")}">Back to Home</a>'
    
    return html


